@namespace Lumeo
@typeparam T
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject Lumeo.Services.IComponentInteropService Interop

<div class="@CssClass" role="tree" aria-multiselectable="@MultiSelect.ToString().ToLowerInvariant()" @attributes="AdditionalAttributes">
    @if (ShowSearch)
    {
        <div class="mb-2">
            <input type="text" placeholder="@L["Common.Search"]"
                   class="flex h-8 w-full rounded-md border border-input bg-transparent px-3 py-1 text-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring"
                   value="@_searchText"
                   @oninput="OnSearchInput" />
        </div>
    }

    @if (Items is { Count: > 0 })
    {
        <CascadingValue Value="_context" IsFixed="false">
            @for (var i = 0; i < _displayItems.Count; i++)
            {
                var item = _displayItems[i];
                <TreeViewNode T="T" @key="item" Item="item" Level="0"
                              PosInSet="@(i + 1)"
                              SetSize="@_displayItems.Count"
                              ShowCheckboxes="ShowCheckboxes"
                              Expandable="Expandable"
                              CascadeCheck="CascadeCheck"
                              MultiSelect="MultiSelect"
                              ExpandOnRowClick="ExpandOnRowClick"
                              SelectedNodes="_selectedNodes"
                              NodeTemplate="NodeTemplate"
                              LoadChildren="LoadChildren"
                              OnItemClick="HandleItemClick"
                              OnItemCheck="HandleItemCheck"
                              OnSelectionChanged="HandleSelectionChanged" />
            }
        </CascadingValue>
    }
</div>

@code {
    [Parameter] public List<TreeViewItem<T>>? Items { get; set; }
    [Parameter] public bool ShowCheckboxes { get; set; }
    [Parameter] public bool Expandable { get; set; } = true;
    /// <summary>
    /// When <c>true</c> (the default), clicking anywhere on a parent row — a node that has, or
    /// can lazily load, children — both selects it AND toggles its expansion (the whole row is
    /// the expand/collapse target, giving a large hit/touch area; the VS Code file-tree pattern).
    /// Leaf rows always just select. Set to <c>false</c> to keep the chevron as the sole expand
    /// trigger, so a row click only selects. The chevron and keyboard (ArrowRight/Left) expand in
    /// both modes; a Ctrl/Meta/Shift (multi-select modifier) click only selects, never expands.
    /// Has no effect when <see cref="Expandable"/> is <c>false</c>.
    /// </summary>
    [Parameter] public bool ExpandOnRowClick { get; set; } = true;
    [Parameter] public EventCallback<TreeViewItem<T>> OnItemClick { get; set; }
    [Parameter] public EventCallback<TreeViewItem<T>> OnItemCheck { get; set; }
    [Parameter] public bool ShowSearch { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    [Parameter] public Func<TreeViewItem<T>, Task<List<TreeViewItem<T>>>>? LoadChildren { get; set; }
    [Parameter] public bool CascadeCheck { get; set; } = true;
    [Parameter] public EventCallback<List<T?>> CheckedValuesChanged { get; set; }
    [Parameter] public RenderFragment<TreeViewItem<T>>? NodeTemplate { get; set; }
    [Parameter] public bool ExpandAll { get; set; }
    [Parameter] public bool MultiSelect { get; set; }
    [Parameter] public List<T>? SelectedValues { get; set; }
    [Parameter] public EventCallback<List<T>> SelectedValuesChanged { get; set; }

    private string _searchText = "";
    private List<TreeViewItem<T>>? _previousItems;
    // #14: last SelectedValues reference we seeded from, so we only re-seed when
    // the parameter actually changes (not on every unrelated re-render).
    private List<T>? _previousSelectedValues;
    // CONTROLLED discriminator (see OnParametersSet): the last SelectedValues list reference we
    // pushed UP via SelectedValuesChanged. An echo of it (or of the pre-interaction reference) is a
    // no-op; any OTHER reference is an authoritative veto/reset that wins.
    private List<T>? _lastPushedSelectedValues;
    private bool _previousExpandAll;
    private List<TreeViewItem<T>> _displayItems = [];

    // ══════════════════════════════════════════════════════════════════════════
    // OWNERSHIP MODEL — UI state lives in the TREE, keyed by a tree-owned identity
    // ══════════════════════════════════════════════════════════════════════════
    // The single structural change behind PR #351's TreeView rebuild. Consumers create
    // TreeViewItem records; a controlled/immutable parent REPLACES those records on every rebuild
    // (fresh @key'd instances), so any UI state stored ON the record is lost the moment an async
    // operation is in flight. Fourteen review rounds accreted an in-flight registry, an orphan
    // sweep, supersession flags, and a per-operation NodePath re-resolver — all guessing which
    // fresh instance an operation "meant" AFTER the fact. All of that is gone.
    //
    // (1) STATE STORE. Per-node UI state (Expanded, Loading, ChildrenLoaded, the materialized lazy
    //     Children, and the search manual-collapse override) lives in <see cref="NodeState"/>
    //     entries owned by the tree — NOT on the consumer's record. An async operation captures the
    //     state ENTRY (a stable handle) once; no rebuild can invalidate it. So: a moved node keeps
    //     loading (its entry follows it); a collapse during a load is a plain write to the entry
    //     (state.Expanded=false); a completion applies children to the entry and is rendered by
    //     whatever instance currently maps to that identity; a second click while loading reads
    //     Loading=true off the entry and starts no duplicate load.
    //
    // (2) IDENTITY, resolved ONCE per parameter-set (<see cref="ResolveIdentities"/>), not per
    //     operation. Each incoming record is matched to an existing entry by, in order:
    //       a. REFERENCE — the same instance is still present (untouched branch / unrelated render);
    //       b. VALUE-VERIFIED SIBLING-UNIQUE PATH — the entry sat at this index path and every
    //          segment (each ancestor + the leaf) still carries its recorded value AND is unique
    //          among its siblings (via <see cref="WalkPath"/>); a shared value at ANY segment is not
    //          a provable anchor, so the path drops;
    //       c. TREE-UNIQUE VALUE — exactly one record and one entry carry the value (a node that
    //          merely moved).
    //     No match ⇒ a fresh entry (seeded from the record). Unmatched entries are DROPPED; an
    //     async operation holding a dropped entry discards its result (identity is unrecoverable —
    //     the same ambiguity-DROP convention selection uses).
    //
    // (3) SEEDS / MIRROR CONTRACT. The record's public flags stay the CONSUMER interface. They are
    //     read as SEEDS (the initial value, and a later value the consumer changes between renders —
    //     detected by diffing the record against the entry's last-seen seed; the consumer wins) and
    //     WRITTEN BACK (mirrored) after every state change, so a consumer that reads
    //     item.IsExpanded / item.IsLoading / item.Children keeps working and can carry state forward
    //     when it rebuilds. IsLoading is tree-OWNED: mirrored OUT but never read as a seed (a stray
    //     record flag can't strand a spinner). Lazy Children live in the entry AND mirror onto
    //     item.Children; a rebuild that drops them re-attaches from the entry.
    //
    // (4) OPERATION SEMANTICS. A row/chevron/keyboard toggle flips the entry SYNCHRONOUSLY (before any
    //     await) and returns a DEFERRED tail; the row click runs the tail only AFTER its selection
    //     callbacks (so a cached load can't attach ahead of a selection rebuild, and a slow/throwing
    //     loader neither delays nor kills the selection). A COLLAPSE is a plain entry write; a lazy
    //     load in flight for that entry keeps running and its completion reads Expanded=false, so it
    //     attaches children but does not re-open (a moved node included — the entry, not a path,
    //     carries the collapse). A second toggle while Loading=true starts NO duplicate load. A
    //     completion ALWAYS materializes — binds a pending seeded SelectedValues and recomputes
    //     checkbox tri-state — regardless of the branch ending expanded or collapsed. A loader failure
    //     rolls the entry back to collapsed (retryable, ChildrenLoaded stays false). An entry DROPPED
    //     by the identity pass mid-load discards its result (re-fetchable beats a mis-attach).
    //
    //     EVENT CONTRACT: TreeView raises NO expand event. Expansion is observable only through the
    //     mirrored item.IsExpanded; the materialization side effects above are NOT gated on any event,
    //     so a superseded (collapsed) completion attaching "silently" is correct — there is nothing to
    //     mis-fire.
    //
    // Selection keeps its own two-bucket model (seeded VALUE contract vs interactive IDENTITY carry,
    // #350) and resolves against the state store: the clicked node is re-resolved through its
    // captured entry, and the once-per-rebuild reanchor uses the same NodePath machinery. Checkbox
    // tri-state stays derived on the record (cascade), recomputed by the shared UpdateAncestorStates.
    // ══════════════════════════════════════════════════════════════════════════
    private sealed class NodeState
    {
        public long Id;
        // The record instance that currently maps to this identity (refreshed each ResolveIdentities
        // and by each operation). An operation mirrors its state writes onto THIS instance.
        public TreeViewItem<T>? Current;
        // The value-verified index path this entry occupied at the last resolution — the phase-(b)
        // re-match key across rebuilds.
        public NodePath? Path;
        public T? Value;
        // Tree-owned UI state.
        public bool Expanded;
        public bool Loading;
        public bool ChildrenLoaded;
        public List<TreeViewItem<T>>? Children;      // materialized lazy children (tree-owned)
        // A user collapse of a search-force-expanded node: the filter must not re-open it on a
        // later same-reference rebuild (RebuildDisplay recomputes _autoExpanded from scratch).
        public bool SearchCollapse;
        // Seed bookkeeping: the record flag values as of the last resolution, so the next parameter
        // set can tell a CONSUMER change apart from our own mirror.
        public bool SeenExpanded;
        public bool SeenChildrenLoaded;
        // Transients used only inside ResolveIdentities.
        public bool Claimed;
        // Set when the once-per-rebuild identity pass could not match this entry to any incoming
        // record. An in-flight operation holding it then discards its result.
        public bool Dropped;
    }

    private long _stateSeq;
    private List<NodeState> _states = [];
    private Dictionary<TreeViewItem<T>, NodeState> _stateByItem = new(ReferenceEqualityComparer.Instance);

    // ── SELECTION (unchanged model, #350) ────────────────────────────────────
    // Selection is tracked by NODE IDENTITY (reference equality), NOT by Value: container/parent
    // nodes routinely share a Value (commonly null, or a duplicate across branches), and keying
    // selection by Value made a single click light up EVERY node sharing that value (GH #350). The
    // public SelectedValues contract is preserved: values are derived from the selected nodes on the
    // way OUT and mapped back to nodes on the way IN.
    private HashSet<TreeViewItem<T>> _selectedNodes = new(ReferenceEqualityComparer.Instance);
    // Wanted VALUES with no bound node yet (a controlled/seed value for an unloaded lazy child, or
    // an async/empty first render). Value-based by the SelectedValues contract — an ambiguous value
    // binds EVERY match.
    private List<T>? _pendingSelectValues;
    // The structural IDENTITY (value-verified path + value) of a resolved node that VANISHED on an
    // Items refresh; re-binds by path, falls back to a UNIQUE value, drops on ambiguity — so a
    // vanished duplicate/null-valued node re-selects the SAME node, not a same-valued sibling.
    private List<PendingCarry>? _pendingCarries;
    // The values currently owned by a consumer SelectedValues seed (origin marker): a seeded value
    // keeps VALUE semantics across a vanish/return (re-binds every match) instead of degrading into
    // an identity carry that ambiguity-drops a duplicate/null seed.
    private HashSet<T>? _seededValues;
    private TreeViewContext? _context;
    // The clicked node's captured state entry, snapshotted in HandleItemClick BEFORE OnItemClick can
    // rebuild Items — so HandleSelectionChanged selects the instance that identity now maps to (or
    // drops when the entry was dropped), instead of adding a stale/disposed instance (round-10 f4).
    private NodeState? _clickState;
    private sealed record PendingCarry(NodePath Path, T? Value);

    /// <summary>A structural node identity: the root→node child-index chain PLUS the value at each
    /// level. Every segment is value-verified and sibling-uniqueness-gated on the way back
    /// (<see cref="WalkPath"/>), so a duplicate/null-valued ancestor that gets reordered can't
    /// silently redirect the walk. Used ONLY for the once-per-rebuild identity match and selection
    /// carries.</summary>
    internal sealed record NodePath(IReadOnlyList<int> Indices, IReadOnlyList<T?> Values);

    // Search filtering renders the ORIGINAL item instances; visibility and search-forced expansion
    // are tracked in these side tables so checking/expanding while filtered mutates the real item.
    private HashSet<TreeViewItem<T>>? _visibleSet;
    private readonly HashSet<TreeViewItem<T>> _autoExpanded = new(ReferenceEqualityComparer.Instance);

    // The structural index path of each currently-resolved selected node, snapshotted after every
    // resolution pass so an IN-PLACE Items mutation (where _previousItems is the same, already-
    // mutated object) can still reanchor a duplicate-valued node by the path it held while present.
    private Dictionary<TreeViewItem<T>, NodePath> _selectionPaths = new(ReferenceEqualityComparer.Instance);

    // Roving tabindex / keyboard navigation state (WAI-ARIA tree pattern).
    private readonly string _treeId = LumeoIds.New("tree");
    private readonly Dictionary<TreeViewItem<T>, string> _nodeIds = new(ReferenceEqualityComparer.Instance);
    private int _nodeIdSeq;
    private List<TreeViewItem<T>>? _flatVisible;
    private TreeViewItem<T>? _activeItem;

    private string CssClass => Cx.Merge("text-sm", Class);

    protected override void OnInitialized()
    {
        _context = new TreeViewContext(this);
    }

    // Set when a declarative ExpandAll pass needs to pull in lazy children; consumed once by
    // OnParametersSetAsync so the load runs a single time.
    private bool _expandAllNeedsLazyLoad;

    protected override void OnParametersSet()
    {
        if (SelectedValuesChanged.HasDelegate)
        {
            // CONTROLLED: adopt SelectedValues only when it is NOT the same reference we just pushed
            // (an accepted echo) AND NOT the reference the parent held before this interaction (an
            // observer-only consumer that never echoes). Only a third, distinct reference is an
            // authoritative veto/override that must win. (Both snapshots read BEFORE the overwrite.)
            var isEcho = ReferenceEquals(SelectedValues, _lastPushedSelectedValues);
            var isUnchangedFromBeforeInteraction = ReferenceEquals(SelectedValues, _previousSelectedValues);
            if (!isEcho && !isUnchangedFromBeforeInteraction)
            {
                _selectedNodes = ResolveSelectedNodes(SelectedValues);
                _lastPushedSelectedValues = SelectedValues;
            }
            _previousSelectedValues = SelectedValues;
        }
        else if (!ReferenceEquals(SelectedValues, _previousSelectedValues))
        {
            // #14: UNCONTROLLED — only re-seed when the parameter reference actually changed, so an
            // unrelated re-render doesn't wipe an internally-clicked selection.
            if (SelectedValues is not null)
                _selectedNodes = ResolveSelectedNodes(SelectedValues);
            _previousSelectedValues = SelectedValues;
        }

        bool referenceChanged = !ReferenceEquals(Items, _previousItems);
        bool expandAllChanged = ExpandAll != _previousExpandAll;
        var previousItems = _previousItems;
        _previousItems = Items;
        _previousExpandAll = ExpandAll;
        _flatVisible = null;

        // IDENTITY PASS (ownership model pillar 2): match every incoming record to its state entry,
        // reconcile consumer seeds, mirror tree-owned state back, and re-attach materialized lazy
        // children. Runs on every parameter set — it is idempotent (a reference match + no seed
        // change is a no-op) and it is what carries Loading / loaded Children / expansion across a
        // controlled rebuild that produced fresh instances.
        ResolveIdentities(Items ?? []);

        // Re-anchor the identity-tracked selection onto the current instances, then bind any pending
        // seed/carry. Change detection must NOT hinge on the Items reference (an in-place mutation
        // keeps it), so this runs whenever the reference changed OR a binding looks stale.
        bool needsResolve = referenceChanged || HasStaleOrPendingSelection();
        if (needsResolve)
        {
            ReanchorSelection(Items ?? [], previousItems);
            TryResolvePendingSelection(Items);
            // TRI-STATE DERIVE-ON-SEED: recompute parents from their (seeded or assigned) children so
            // a tree that arrives with children already IsChecked=true shows the right parent state on
            // the first render. Cascade-only.
            if (CascadeCheck && ShowCheckboxes)
                UpdateAncestorStates(Items ?? []);
        }

        if (referenceChanged)
        {
            if (ExpandAll)
            {
                ApplyExpandAll(Items ?? [], true);
                if (LoadChildren is not null)
                    _expandAllNeedsLazyLoad = true;
            }
            RebuildDisplay();
        }
        else if (expandAllChanged)
        {
            ApplyExpandAll(Items ?? [], ExpandAll);
            if (ExpandAll && LoadChildren is not null)
                _expandAllNeedsLazyLoad = true;
            RebuildDisplay();
        }
        else if (!string.IsNullOrWhiteSpace(_searchText))
        {
            // While a SEARCH FILTER is active _displayItems is a filtered ToList() snapshot, so an
            // in-place mutation (retitle / replace items[i]) never reaches the render until the
            // display is re-materialized. Change detection must not hinge on selection state, so
            // re-materialize unconditionally while filtered. RebuildDisplay preserves a manual
            // search collapse (via state), so a re-render no longer re-opens a collapsed ancestor.
            RebuildDisplay();
        }

        // Snapshot the settled selection's paths against the CURRENT tree — the OLD paths a later
        // IN-PLACE mutation reanchors against, captured while the nodes are still present.
        SnapshotSelectionPaths();
    }

    /// <summary>Whether the reanchor/pending pass should run even when the <see cref="Items"/>
    /// reference is UNCHANGED (an in-place mutation of the same list). True when a pending bucket
    /// holds an unbound value/carry, or when any selected node instance is no longer in the tree.</summary>
    private bool HasStaleOrPendingSelection()
    {
        if (_pendingSelectValues is { Count: > 0 } || _pendingCarries is { Count: > 0 }) return true;
        if (_selectedNodes.Count == 0) return false;
        var flat = new List<TreeViewItem<T>>();
        FlattenAll(Items ?? [], flat);
        var present = new HashSet<TreeViewItem<T>>(flat, ReferenceEqualityComparer.Instance);
        foreach (var sel in _selectedNodes)
            if (!present.Contains(sel)) return true;
        return false;
    }

    // ══════════════════════════════════════════════════════════════════════════
    // IDENTITY PASS + STATE STORE
    // ══════════════════════════════════════════════════════════════════════════

    /// <summary>Matches every incoming record to its <see cref="NodeState"/> entry (reference →
    /// value-verified sibling-unique path → tree-unique value → fresh), reconciles consumer seeds,
    /// mirrors tree-owned state back onto the record, and re-attaches materialized lazy children.
    /// Unmatched entries are dropped. Runs exactly once per parameter set.</summary>
    private void ResolveIdentities(List<TreeViewItem<T>> items)
    {
        var pool = _states;
        foreach (var s in pool) s.Claimed = false;

        // The full incoming (consumer) tree, for the tree-unique-value phase. Re-attached lazy children
        // always match by reference, so their omission here is immaterial. Value comparisons go through
        // EqualityComparer<T>.Default (null-safe) — never a T-keyed dictionary, since T is an
        // unconstrained (nullable) component type parameter.
        var flat = new List<TreeViewItem<T>>();
        FlattenAll(items, flat);

        // Index the OLD pool by the two non-value keys (reference + path) for O(1) claims; the value
        // phase scans linearly (it only runs for nodes a rebuild replaced, the uncommon case).
        var poolByRef = new Dictionary<TreeViewItem<T>, NodeState>(ReferenceEqualityComparer.Instance);
        var poolByPath = new Dictionary<string, NodeState>();
        foreach (var s in pool)
        {
            if (s.Current is not null) poolByRef[s.Current] = s;
            if (s.Path is { Indices.Count: > 0 }) poolByPath[PathKey(s.Path.Indices)] = s;
        }

        var newStates = new List<NodeState>();
        var byItem = new Dictionary<TreeViewItem<T>, NodeState>(ReferenceEqualityComparer.Instance);
        ResolveLevel(items, [], [], items, flat, pool, poolByRef, poolByPath, newStates, byItem);

        foreach (var s in pool)
            if (!s.Claimed) { s.Dropped = true; s.Current = null; }
        _states = newStates;
        _stateByItem = byItem;
    }

    private void ResolveLevel(List<TreeViewItem<T>> level, IReadOnlyList<int> parentIdx,
        IReadOnlyList<T?> parentVals, List<TreeViewItem<T>> roots, List<TreeViewItem<T>> flat,
        List<NodeState> pool, Dictionary<TreeViewItem<T>, NodeState> poolByRef,
        Dictionary<string, NodeState> poolByPath,
        List<NodeState> newStates, Dictionary<TreeViewItem<T>, NodeState> byItem)
    {
        for (var i = 0; i < level.Count; i++)
        {
            var node = level[i];
            var indices = new List<int>(parentIdx) { i };
            var values = new List<T?>(parentVals) { node.Value };
            var path = new NodePath(indices, values);
            bool sibUnique = CountValue(level, node.Value) == 1;

            var state = ClaimState(node, path, sibUnique, roots, flat, pool, poolByRef, poolByPath);
            bool isNew = state is null;
            state ??= new NodeState { Id = ++_stateSeq };
            state.Claimed = true;
            BindState(state, node, path, isNew);
            newStates.Add(state);
            byItem[node] = state;

            if (node.Children is { Count: > 0 })
                ResolveLevel(node.Children, indices, values, roots, flat, pool, poolByRef, poolByPath,
                    newStates, byItem);
        }
    }

    /// <summary>Claims an existing entry for <paramref name="node"/> by the ownership priority
    /// (reference → value-verified sibling-unique path → tree-unique value), or null when none matches
    /// (the caller then mints a fresh entry).</summary>
    private NodeState? ClaimState(TreeViewItem<T> node, NodePath path, bool sibUnique,
        List<TreeViewItem<T>> roots, List<TreeViewItem<T>> flat, List<NodeState> pool,
        Dictionary<TreeViewItem<T>, NodeState> poolByRef, Dictionary<string, NodeState> poolByPath)
    {
        // (a) reference — same instance still present.
        if (poolByRef.TryGetValue(node, out var byRef) && !byRef.Claimed)
            return byRef;

        // (b) value-verified sibling-unique path — the entry that sat here, if EVERY segment
        // re-verifies (WalkPath) and the leaf is sibling-unique now.
        if (sibUnique && poolByPath.TryGetValue(PathKey(path.Indices), out var byPath)
            && !byPath.Claimed && byPath.Path is not null
            && ReferenceEquals(WalkPath(roots, byPath.Path), node))
            return byPath;

        // (c) tree-unique value — a node that merely moved: exactly one record AND one unclaimed entry
        // carry the value.
        if (CountValue(flat, node.Value) == 1)
        {
            NodeState? only = null;
            var count = 0;
            foreach (var s in pool)
            {
                if (s.Claimed || !EqualityComparer<T>.Default.Equals(s.Value, node.Value)) continue;
                only = s;
                if (++count > 1) break;
            }
            if (count == 1) return only;
        }
        return null;
    }

    /// <summary>Occurrences of <paramref name="value"/> among <paramref name="nodes"/> (null-safe;
    /// avoids a T-keyed dictionary since T is an unconstrained nullable type parameter).</summary>
    private static int CountValue(IReadOnlyList<TreeViewItem<T>> nodes, T? value)
    {
        var n = 0;
        foreach (var item in nodes)
            if (EqualityComparer<T>.Default.Equals(item.Value, value)) n++;
        return n;
    }

    /// <summary>Reconciles consumer seeds into <paramref name="state"/> (consumer change wins) and
    /// mirrors the tree-owned state back onto <paramref name="node"/>.</summary>
    private void BindState(NodeState state, TreeViewItem<T> node, NodePath path, bool isNew)
    {
        if (isNew)
        {
            state.Expanded = node.IsExpanded;
            state.Loading = false;
            state.ChildrenLoaded = node.ChildrenLoaded || node.Children is { Count: > 0 };
            state.Children = node.Children;
        }
        else
        {
            // Expansion: a record value differing from the last-seen seed is a consumer change.
            if (node.IsExpanded != state.SeenExpanded) state.Expanded = node.IsExpanded;
            // Children: the consumer OWNS children they supply; the tree owns lazy-loaded children.
            bool consumerSupplied = node.Children is { Count: > 0 } || node.ChildrenLoaded;
            if (consumerSupplied
                && (node.ChildrenLoaded != state.SeenChildrenLoaded
                    || (node.Children is { Count: > 0 } && !ReferenceEquals(node.Children, state.Children))))
            {
                state.Children = node.Children;
                state.ChildrenLoaded = node.ChildrenLoaded || node.Children is { Count: > 0 };
            }
        }

        state.Current = node;
        state.Path = path;
        state.Value = node.Value;
        state.Dropped = false;
        MirrorState(state);
    }

    /// <summary>Writes tree-owned UI state onto the entry's current record (the seeds/mirror
    /// contract) and refreshes the seen-seed bookkeeping so the next parameter set can tell a
    /// consumer change from our own mirror.</summary>
    private void MirrorState(NodeState state)
    {
        var it = state.Current;
        if (it is null) return;
        it.IsExpanded = state.Expanded;
        it.IsLoading = state.Loading;
        if (state.ChildrenLoaded)
        {
            it.ChildrenLoaded = true;
            if (state.Children is not null && !ReferenceEquals(it.Children, state.Children)
                && it.Children is not { Count: > 0 })
                it.Children = state.Children;   // re-attach tree-owned lazy children onto a fresh record
        }
        state.SeenExpanded = it.IsExpanded;
        state.SeenChildrenLoaded = it.ChildrenLoaded;
    }

    /// <summary>The state entry for <paramref name="item"/>, minting one (seeded from the record)
    /// when the item has no entry yet (e.g. a freshly-loaded lazy child before the next parameter
    /// set re-indexes the tree).</summary>
    private NodeState GetState(TreeViewItem<T> item)
    {
        if (_stateByItem.TryGetValue(item, out var s) && !s.Dropped) return s;
        s = new NodeState
        {
            Id = ++_stateSeq,
            Current = item,
            Value = item.Value,
            Expanded = item.IsExpanded,
            ChildrenLoaded = item.ChildrenLoaded || item.Children is { Count: > 0 },
            Children = item.Children,
            SeenExpanded = item.IsExpanded,
            SeenChildrenLoaded = item.ChildrenLoaded || item.Children is { Count: > 0 },
        };
        _states.Add(s);
        _stateByItem[item] = s;
        return s;
    }

    /// <summary>Registers state entries for a freshly-loaded lazy subtree so an immediate operation
    /// (or the render before the next parameter set) sees them.</summary>
    private void RegisterSubtree(List<TreeViewItem<T>> loaded)
    {
        foreach (var child in loaded)
        {
            GetState(child);
            if (child.Children is { Count: > 0 })
                RegisterSubtree(child.Children);
        }
    }

    private static string PathKey(IReadOnlyList<int> indices) => string.Join(",", indices);

    // ══════════════════════════════════════════════════════════════════════════
    // EXPAND / COLLAPSE / LAZY LOAD — operations hold a STATE HANDLE, never a path
    // ══════════════════════════════════════════════════════════════════════════

    /// <summary>The SYNCHRONOUS half of a row/chevron/keyboard toggle: flips the node's expansion in
    /// the STATE store now (before any await), so a selection-driven controlled rebuild re-maps the
    /// fresh instance to this same entry and mirrors the new state onto it. Returns the DEFERRED half
    /// — start the lazy child-load, or notify an already-loaded expand/collapse — so the caller
    /// chooses WHEN to run it: the chevron/keyboard run it immediately; the row click runs it only
    /// AFTER the selection callbacks (so a cached load can't attach ahead of a selection rebuild).</summary>
    internal Func<Task> BeginToggle(TreeViewItem<T> item)
    {
        var state = GetState(item);

        if (IsEffectivelyExpanded(item))
        {
            // COLLAPSE — a plain write to the entry. If a lazy load is still in flight, its
            // completion reads Expanded=false and does not re-open; no supersession flag needed.
            state.Expanded = false;
            if (_autoExpanded.Contains(item)) state.SearchCollapse = true;   // override the filter's force-open
            _autoExpanded.Remove(item);
            MirrorState(state);
            _flatVisible = null;
            StateHasChanged();
            return () => NotifyCollapseAsync(state);
        }

        // EXPAND.
        state.Expanded = false; // reset a stale manual-collapse before re-forcing below
        state.SearchCollapse = false;
        state.Expanded = true;

        bool needsLoad = LoadChildren is not null && !state.ChildrenLoaded && !item.IsLeaf
            && item.Children is not { Count: > 0 } && state.Children is not { Count: > 0 };

        if (needsLoad)
        {
            if (state.Loading)
            {
                // A load is already in flight for this identity (the user collapsed the spinner and
                // clicked again): re-assert expansion, start NO second load. The original completion
                // reveals the children.
                MirrorState(state);
                _flatVisible = null;
                StateHasChanged();
                return () => Task.CompletedTask;
            }
            state.Loading = true;
            MirrorState(state);
            _flatVisible = null;
            StateHasChanged();
            return () => LoadChildrenAsync(state, item);
        }

        MirrorState(state);
        _flatVisible = null;
        StateHasChanged();
        return () => NotifyExpandAsync(state);
    }

    /// <summary>Deferred tail of an already-loaded (non-lazy) expand. RE-ASSERTS the expansion on the
    /// state entry: a selection-driven controlled rebuild may have supplied a fresh instance whose
    /// IsExpanded seed was NOT carried forward (a consumer that rebuilds from a collapsed source), so
    /// the identity pass' seed reconciliation reset the entry — the click's expand intent wins. Then
    /// materialize any pending selection / tri-state for the now-visible subtree.</summary>
    private Task NotifyExpandAsync(NodeState state)
    {
        if (!state.Dropped)
        {
            state.Expanded = true;
            state.SearchCollapse = false;
            MirrorState(state);
            var item = state.Current;
            if (item is not null)
            {
                TryResolvePendingSelection(item.Children);
                if (CascadeCheck && ShowCheckboxes)
                    UpdateAncestorStates(Items ?? []);
            }
        }
        _flatVisible = null;
        SnapshotSelectionPaths();
        StateHasChanged();
        return Task.CompletedTask;
    }

    /// <summary>Deferred tail of a collapse: just settle the render. The entry already holds
    /// Expanded=false; no re-assert (that would fight the user's collapse).</summary>
    private Task NotifyCollapseAsync(NodeState state)
    {
        _ = state;
        _flatVisible = null;
        SnapshotSelectionPaths();
        StateHasChanged();
        return Task.CompletedTask;
    }

    /// <summary>The awaited tail of a lazy expansion. Fetches the children and applies them to the
    /// captured STATE entry — rendered by whatever instance currently maps to that identity. The
    /// materialization side effects (pending-selection bind, tri-state cascade) run ALWAYS, even
    /// when a collapse during the load left the branch closed. A loader failure rolls the entry back
    /// to collapsed (retryable, ChildrenLoaded stays false) and re-throws; the entry being dropped
    /// mid-load discards the result (the node vanished / its identity is unprovable).</summary>
    private async Task LoadChildrenAsync(NodeState state, TreeViewItem<T> loadArg)
    {
        try
        {
            var loaded = await LoadChildren!(state.Current ?? loadArg);

            if (state.Dropped) return;   // node vanished / unprovable identity → discard the load

            state.Children = loaded;
            state.ChildrenLoaded = true;
            state.Loading = false;
            RegisterSubtree(loaded);

            var target = state.Current;
            if (target is not null)
            {
                target.Children = loaded;
                target.ChildrenLoaded = true;
                MirrorState(state);
                // Materialization ALWAYS runs (even if the branch was collapsed during the load), so
                // a seeded lazy selection binds and a collapsed parent still reflects a checked child.
                TryResolvePendingSelection(loaded);
                if (target.IsChecked && !target.IsIndeterminate)
                    SetChildrenChecked(loaded, true);
                else if (CascadeCheck && ShowCheckboxes)
                    UpdateAncestorStates(Items ?? []);
            }

            _flatVisible = null;
            RebuildDisplay();
            SnapshotSelectionPaths();
            StateHasChanged();
        }
        catch
        {
            if (!state.Dropped)
            {
                state.Loading = false;
                state.Expanded = false;
                MirrorState(state);
                _flatVisible = null;
                StateHasChanged();
            }
            throw;
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        if (!_expandAllNeedsLazyLoad) return;
        _expandAllNeedsLazyLoad = false;
        var gen = ++_expandGeneration;
        await LoadAndExpandAllAsync(Items ?? [], gen);
        if (gen != _expandGeneration) return; // superseded by a collapse/expand
        if (CascadeCheck && ShowCheckboxes)
            UpdateAncestorStates(Items ?? []);
        _flatVisible = null;
        RebuildDisplay();
        StateHasChanged();
    }

    /// <summary>Expands every node. Already-loaded nodes expand synchronously; when
    /// <see cref="LoadChildren"/> is configured, lazy children are then fetched in the background.
    /// Await <see cref="ExpandAllNodesAsync"/> instead when you need the lazy load to complete.</summary>
    public void ExpandAllNodes()
    {
        ApplyExpandAll(Items ?? [], true);
        _flatVisible = null;
        StateHasChanged();
        if (LoadChildren is not null)
            _ = ExpandAllNodesAsync();
    }

    // Bumped on every expand-all / collapse-all so a stale background lazy-expand pass detects it
    // lost the race and bails instead of re-expanding a tree the user just collapsed.
    private int _expandGeneration;

    public async Task ExpandAllNodesAsync()
    {
        var gen = ++_expandGeneration;
        ApplyExpandAll(Items ?? [], true);
        if (LoadChildren is not null)
            await LoadAndExpandAllAsync(Items ?? [], gen);
        if (gen != _expandGeneration) return;
        if (CascadeCheck && ShowCheckboxes)
            UpdateAncestorStates(Items ?? []);
        _flatVisible = null;
        StateHasChanged();
    }

    public void CollapseAllNodes()
    {
        _expandGeneration++; // cancel any in-flight lazy expand-all pass
        ApplyExpandAll(Items ?? [], false);
        // A per-node lazy load pending during collapse-all needs no supersession: its completion
        // reads Expanded=false off the entry and does not re-open the node.
        _flatVisible = null;
        StateHasChanged();
    }

    /// <summary>Recursively expands nodes, fetching lazy children via <see cref="LoadChildren"/> and
    /// descending into freshly-loaded subtrees. Attaches loaded children to the captured STATE entry,
    /// so a controlled rebuild mid-pass never strands or mis-attaches them.</summary>
    private async Task LoadAndExpandAllAsync(List<TreeViewItem<T>> items, int gen)
    {
        foreach (var item in items)
        {
            if (gen != _expandGeneration) return;
            var state = GetState(item);
            state.Expanded = true;
            state.SearchCollapse = false;

            if (LoadChildren is not null && !state.ChildrenLoaded && !item.IsLeaf
                && item.Children is not { Count: > 0 } && state.Children is not { Count: > 0 }
                && !state.Loading)
            {
                state.Loading = true;
                MirrorState(state);
                _flatVisible = null;
                StateHasChanged();
                try
                {
                    var loaded = await LoadChildren(state.Current ?? item);
                    if (gen != _expandGeneration) return;
                    if (state.Dropped) continue;
                    state.Children = loaded;
                    state.ChildrenLoaded = true;
                    state.Loading = false;
                    RegisterSubtree(loaded);
                    var target = state.Current;
                    if (target is not null)
                    {
                        target.Children = loaded;
                        target.ChildrenLoaded = true;
                        MirrorState(state);
                        TryResolvePendingSelection(loaded);
                        if (target.IsChecked && !target.IsIndeterminate && loaded is { Count: > 0 })
                            SetChildrenChecked(loaded, true);
                    }
                }
                finally
                {
                    if (!state.Dropped)
                    {
                        state.Loading = false;
                        MirrorState(state);
                    }
                }
            }
            else
            {
                MirrorState(state);
            }

            var descend = state.Current?.Children ?? state.Children;
            if (descend is { Count: > 0 })
                await LoadAndExpandAllAsync(descend, gen);
        }
    }

    private async Task HandleItemClick(TreeViewItem<T> item)
    {
        // Capture the clicked node's STATE entry NOW — before OnItemClick can rebuild Items — so
        // HandleSelectionChanged selects whatever instance identity maps to (or drops if the entry
        // was dropped), instead of adding the stale/disposed instance.
        _clickState = GetState(item);
        await OnItemClick.InvokeAsync(item);
    }

    private async Task HandleItemCheck(TreeViewItem<T> item)
    {
        if (CascadeCheck && ShowCheckboxes)
        {
            SetChildrenChecked(item.Children, item.IsChecked);
            UpdateAncestorStates(Items ?? []);
        }
        await OnItemCheck.InvokeAsync(item);

        if (CheckedValuesChanged.HasDelegate)
        {
            var allChecked = CollectChecked(Items ?? []);
            await CheckedValuesChanged.InvokeAsync(allChecked);
        }

        StateHasChanged();
    }

    private async Task HandleSelectionChanged(TreeViewItem<T> item)
    {
        // Selection is by node identity (never touches expansion). Re-resolve the clicked instance
        // through its captured STATE entry: OnItemClick (awaited before this callback) may have
        // rebuilt Items, disposing the clicked @key'd node. The entry now points at the fresh
        // instance, or was DROPPED when identity is unprovable (a duplicate/null-valued click whose
        // siblings reordered) — in which case the click selects nothing (the ambiguity-DROP rule).
        var resolvedClick = _clickState is { Dropped: false, Current: not null } ? _clickState.Current : null;
        _clickState = null;
        if (resolvedClick is null)
        {
            StateHasChanged();
            return;
        }
        item = resolvedClick;

        bool changed;
        if (MultiSelect)
        {
            if (!_selectedNodes.Add(item))
                _selectedNodes.Remove(item);
            changed = true;
            RemovePending(item.Value);
        }
        else
        {
            changed = _selectedNodes.Count != 1 || !_selectedNodes.Contains(item);
            if (changed)
            {
                _selectedNodes.Clear();
                _selectedNodes.Add(item);
            }
            // Single-select click owns the whole selection: void any pending seed / carried identity
            // and take the selection INTERACTIVE (drop seed origins).
            _pendingSelectValues = null;
            _pendingCarries = null;
            _seededValues = null;
        }

        if (changed && SelectedValuesChanged.HasDelegate)
        {
            List<T> outgoing = [.._selectedNodes.Select(n => n.Value!)];
            _lastPushedSelectedValues = outgoing;
            await SelectedValuesChanged.InvokeAsync(outgoing);
        }
        SnapshotSelectionPaths();
        StateHasChanged();
    }

    private void OnSearchInput(ChangeEventArgs e)
    {
        _searchText = e.Value?.ToString() ?? "";
        RebuildDisplay();
    }

    private void RebuildDisplay()
    {
        _flatVisible = null;
        _autoExpanded.Clear();

        if (string.IsNullOrWhiteSpace(_searchText))
        {
            _visibleSet = null;
            _displayItems = Items ?? [];
        }
        else
        {
            _visibleSet = new HashSet<TreeViewItem<T>>(ReferenceEqualityComparer.Instance);
            CollectVisible(Items ?? [], _searchText, _visibleSet, _autoExpanded);
            _displayItems = (Items ?? []).Where(_visibleSet.Contains).ToList();
        }
    }

    /// <summary>Marks every item whose text matches the filter — or that has a matching descendant —
    /// as visible. A matching item keeps its whole subtree visible; ancestors of deeper matches are
    /// force-expanded via <see cref="_autoExpanded"/> UNLESS the user manually collapsed them (the
    /// per-node <see cref="NodeState.SearchCollapse"/> override, which survives a rebuild).</summary>
    private void CollectVisible(List<TreeViewItem<T>> items, string filter,
        HashSet<TreeViewItem<T>> visible, HashSet<TreeViewItem<T>> autoExpanded)
    {
        foreach (var item in items)
        {
            bool selfMatches = item.Text.Contains(filter, StringComparison.OrdinalIgnoreCase);
            bool childMatches = item.Children is { Count: > 0 }
                && CollectVisibleInner(item.Children, filter, visible, autoExpanded);

            if (!selfMatches && !childMatches) continue;

            visible.Add(item);
            if (childMatches && !ManualCollapsed(item))
                autoExpanded.Add(item);
            else if (item.Children is { Count: > 0 })
                MarkSubtreeVisible(item.Children, visible);
        }
    }

    private bool CollectVisibleInner(List<TreeViewItem<T>> items, string filter,
        HashSet<TreeViewItem<T>> visible, HashSet<TreeViewItem<T>> autoExpanded)
    {
        bool any = false;
        foreach (var item in items)
        {
            bool selfMatches = item.Text.Contains(filter, StringComparison.OrdinalIgnoreCase);
            bool childMatches = item.Children is { Count: > 0 }
                && CollectVisibleInner(item.Children, filter, visible, autoExpanded);

            if (!selfMatches && !childMatches) continue;

            visible.Add(item);
            any = true;
            if (childMatches && !ManualCollapsed(item))
                autoExpanded.Add(item);
            else if (item.Children is { Count: > 0 })
                MarkSubtreeVisible(item.Children, visible);
        }
        return any;
    }

    /// <summary>Whether the user manually collapsed this search-force-expanded node (state override).</summary>
    private bool ManualCollapsed(TreeViewItem<T> item)
        => _stateByItem.TryGetValue(item, out var s) && s.SearchCollapse;

    private static void MarkSubtreeVisible(List<TreeViewItem<T>> items, HashSet<TreeViewItem<T>> visible)
    {
        foreach (var item in items)
        {
            visible.Add(item);
            if (item.Children is { Count: > 0 })
                MarkSubtreeVisible(item.Children, visible);
        }
    }

    // ---- Shared state consumed by TreeViewNode through the cascaded context ----

    internal bool IsEffectivelyExpanded(TreeViewItem<T> item)
        => item.IsExpanded || _autoExpanded.Contains(item);

    internal IReadOnlyList<TreeViewItem<T>> GetVisibleChildren(TreeViewItem<T> item)
    {
        if (item.Children is not { Count: > 0 }) return [];
        return _visibleSet is null
            ? item.Children
            : item.Children.Where(_visibleSet.Contains).ToList();
    }

    /// <summary>Deterministic per-item element id used as the focus target for keyboard navigation.</summary>
    internal string GetNodeId(TreeViewItem<T> item)
    {
        if (!_nodeIds.TryGetValue(item, out var id))
        {
            id = $"{_treeId}-node-{_nodeIdSeq++}";
            _nodeIds[item] = id;
        }
        return id;
    }

    /// <summary>Roving tabindex: exactly one visible node (the active one) is in the tab sequence.</summary>
    internal int GetTabIndex(TreeViewItem<T> item)
    {
        EnsureFlatVisible();
        return ReferenceEquals(item, _activeItem) ? 0 : -1;
    }

    /// <summary>Keeps the roving tabindex in sync when a node receives DOM focus directly.</summary>
    internal void SetActive(TreeViewItem<T> item)
    {
        if (ReferenceEquals(_activeItem, item)) return;
        _activeItem = item;
        StateHasChanged();
    }

    /// <summary>WAI-ARIA tree navigation. Down/Up move through the visible nodes, Home/End jump to
    /// the first/last, Right moves into the first child of an expanded node and Left moves to the
    /// parent of a collapsed/leaf node.</summary>
    internal async Task HandleNavigationKeyAsync(TreeViewItem<T> item, string key)
    {
        EnsureFlatVisible();
        var flat = _flatVisible!;
        if (flat.Count == 0) return;
        var index = flat.FindIndex(i => ReferenceEquals(i, item));
        if (index < 0) return;

        var target = key switch
        {
            "ArrowDown" => index < flat.Count - 1 ? flat[index + 1] : null,
            "ArrowUp"   => index > 0 ? flat[index - 1] : null,
            "Home"      => flat[0],
            "End"       => flat[^1],
            "ArrowRight" => IsEffectivelyExpanded(item) ? GetVisibleChildren(item).FirstOrDefault() : null,
            "ArrowLeft"  => FindParent(Items ?? [], item),
            _ => null
        };

        if (target is not null && !ReferenceEquals(target, item))
        {
            _activeItem = target;
            StateHasChanged();
            await Interop.FocusElement(GetNodeId(target));
        }
    }

    private void EnsureFlatVisible()
    {
        if (_flatVisible is not null) return;
        _flatVisible = [];
        AppendVisible(_displayItems, _flatVisible);
        if (_activeItem is null || !_flatVisible.Any(i => ReferenceEquals(i, _activeItem)))
        {
            // #13: re-anchor the roving tabindex by STABLE identity (Value) so keyboard focus
            // survives a same-content refresh instead of snapping back to the first node.
            var byValue = _activeItem is not null
                ? _flatVisible.FirstOrDefault(i => EqualityComparer<T>.Default.Equals(i.Value, _activeItem.Value))
                : null;
            _activeItem = byValue ?? (_flatVisible.Count > 0 ? _flatVisible[0] : null);
        }
    }

    private void AppendVisible(IReadOnlyList<TreeViewItem<T>> items, List<TreeViewItem<T>> result)
    {
        foreach (var item in items)
        {
            result.Add(item);
            if (IsEffectivelyExpanded(item) && item.Children is { Count: > 0 })
                AppendVisible(GetVisibleChildren(item), result);
        }
    }

    private static TreeViewItem<T>? FindParent(List<TreeViewItem<T>> items, TreeViewItem<T> child)
    {
        foreach (var item in items)
        {
            if (item.Children is not { Count: > 0 }) continue;
            if (item.Children.Any(c => ReferenceEquals(c, child))) return item;
            var found = FindParent(item.Children, child);
            if (found is not null) return found;
        }
        return null;
    }

    // ══════════════════════════════════════════════════════════════════════════
    // SELECTION (two-bucket model, #350) — resolves against the state store
    // ══════════════════════════════════════════════════════════════════════════

    /// <summary>Maps an incoming (controlled/seed) <see cref="SelectedValues"/> list to the concrete
    /// node instances carrying those values. Value-based on the way IN — an ambiguous value selects
    /// every match (the value contract). Interactive clicks stay identity-exact.</summary>
    private HashSet<TreeViewItem<T>> ResolveSelectedNodes(List<T>? values)
    {
        _pendingCarries = null;
        var set = new HashSet<TreeViewItem<T>>(ReferenceEqualityComparer.Instance);
        if (values is not { Count: > 0 })
        {
            _pendingSelectValues = null;
            _seededValues = null;
            return set;
        }
        _seededValues = new HashSet<T>(values);
        var wanted = new HashSet<T>(values);
        CollectMatching(Items ?? [], wanted, set);
        var matched = new HashSet<T>(set.Select(n => n.Value!));
        var pending = HasUnloadedLazyBranches(Items ?? [])
            ? values.Distinct().ToList()
            : values.Where(v => !matched.Contains(v)).ToList();
        _pendingSelectValues = pending.Count > 0 ? pending : null;
        return set;
    }

    /// <summary>Drains both pending buckets. Path-carried IDENTITIES re-bind first (by value-verified
    /// path, unique-value fallback, drop on ambiguity); then any value seed binds against the
    /// freshly-loaded subtree. Additive — never clears an existing selection, never pushes up.</summary>
    private void TryResolvePendingSelection(List<TreeViewItem<T>>? loaded)
    {
        ResolveCarriedPending();

        if (_pendingSelectValues is not { Count: > 0 } || loaded is not { Count: > 0 }) return;
        var wanted = new HashSet<T>(_pendingSelectValues);
        var found = new HashSet<TreeViewItem<T>>(ReferenceEqualityComparer.Instance);
        CollectMatching(loaded, wanted, found);
        if (found.Count == 0) return;
        foreach (var n in found) _selectedNodes.Add(n);
        if (HasUnloadedLazyBranches(Items ?? [])) return;
        var resolvedValues = new HashSet<T>(found.Select(n => n.Value!));
        var remaining = _pendingSelectValues.Where(v => !resolvedValues.Contains(v)).ToList();
        _pendingSelectValues = remaining.Count > 0 ? remaining : null;
    }

    /// <summary>True while the tree holds a lazy, not-yet-loaded branch — a value seed can't be
    /// treated as fully satisfied while such a branch might yet materialize another node with that
    /// value (the value contract binds EVERY match).</summary>
    private bool HasUnloadedLazyBranches(List<TreeViewItem<T>> items)
    {
        if (LoadChildren is null) return false;
        foreach (var item in items)
        {
            if (!item.IsLeaf && !item.ChildrenLoaded && item.Children is not { Count: > 0 })
                return true;
            if (item.Children is { Count: > 0 } && HasUnloadedLazyBranches(item.Children))
                return true;
        }
        return false;
    }

    /// <summary>Re-binds carried node identities against the current full <see cref="Items"/> tree:
    /// PREFER the value-verified path, fall back to a UNIQUE value; a value not yet in the tree stays
    /// queued, an ambiguous one is dropped.</summary>
    private void ResolveCarriedPending()
    {
        if (_pendingCarries is not { Count: > 0 }) return;
        var tree = Items ?? [];
        if (tree.Count == 0) return;
        var flat = new List<TreeViewItem<T>>();
        FlattenAll(tree, flat);
        List<PendingCarry>? remaining = null;
        foreach (var carry in _pendingCarries)
        {
            var (node, drop) = ResolveCarryNode(carry, tree, flat);
            if (node is not null)
                _selectedNodes.Add(node);
            else if (!drop)
                (remaining ??= []).Add(carry);
        }
        _pendingCarries = remaining;
    }

    private static (TreeViewItem<T>? Node, bool Drop) ResolveCarryNode(PendingCarry carry, List<TreeViewItem<T>> tree, List<TreeViewItem<T>> flat)
    {
        var byPath = WalkPath(tree, carry.Path);
        if (byPath is not null) return (byPath, false);
        var byValue = flat.Where(n => EqualityComparer<T>.Default.Equals(n.Value, carry.Value)).ToList();
        if (byValue.Count == 1) return (byValue[0], false);
        return (null, byValue.Count > 1);
    }

    private static void CollectMatching(List<TreeViewItem<T>> items, HashSet<T> wanted, HashSet<TreeViewItem<T>> into)
    {
        foreach (var item in items)
        {
            if (wanted.Contains(item.Value!)) into.Add(item);
            if (item.Children is { Count: > 0 })
                CollectMatching(item.Children, wanted, into);
        }
    }

    /// <summary>Re-anchors the identity-tracked selection onto a freshly-supplied <see cref="Items"/>
    /// tree: a node still present by reference is kept; a replaced node re-matches by value-verified
    /// PATH (snapshot, falling back to <paramref name="oldItems"/>) with a UNIQUE-value fallback; a
    /// vanished node carries back to the pending buckets by ORIGIN (seeded=value / interactive=identity).</summary>
    private void ReanchorSelection(List<TreeViewItem<T>> newItems, List<TreeViewItem<T>>? oldItems)
    {
        if (_selectedNodes.Count == 0) return;
        var flat = new List<TreeViewItem<T>>();
        FlattenAll(newItems, flat);
        var present = new HashSet<TreeViewItem<T>>(flat, ReferenceEqualityComparer.Instance);
        var rebuilt = new HashSet<TreeViewItem<T>>(ReferenceEqualityComparer.Instance);
        List<PendingCarry>? carried = null;
        List<T>? carriedValues = null;
        foreach (var sel in _selectedNodes)
        {
            if (present.Contains(sel))
            {
                rebuilt.Add(sel);
                continue;
            }
            var oldPath = OldPathOf(sel, oldItems);
            var match = oldPath is { Indices.Count: > 0 } ? WalkPath(newItems, oldPath) : null;
            if (match is null)
            {
                var byValue = flat.Where(n => EqualityComparer<T>.Default.Equals(n.Value, sel.Value)).ToList();
                if (byValue.Count == 1) match = byValue[0];
            }
            if (match is not null)
            {
                rebuilt.Add(match);
                continue;
            }
            if (_seededValues is not null && _seededValues.Contains(sel.Value!))
                (carriedValues ??= []).Add(sel.Value!);
            else
                (carried ??= []).Add(new PendingCarry(oldPath ?? new NodePath([], []), sel.Value));
        }
        _selectedNodes = rebuilt;
        if (carried is { Count: > 0 })
            MergeCarries(carried);
        if (carriedValues is { Count: > 0 })
            MergePendingValues(carriedValues);
    }

    private void MergeCarries(List<PendingCarry> carries)
    {
        if (carries.Count == 0) return;
        _pendingCarries = _pendingCarries is { Count: > 0 }
            ? [.._pendingCarries, ..carries]
            : carries;
    }

    private void MergePendingValues(List<T> values)
    {
        if (values.Count == 0) return;
        var merged = _pendingSelectValues is { Count: > 0 }
            ? new List<T>(_pendingSelectValues)
            : new List<T>();
        foreach (var v in values)
            if (!merged.Contains(v)) merged.Add(v);
        _pendingSelectValues = merged.Count > 0 ? merged : null;
    }

    /// <summary>The OLD structural path of a vanished selected node: PREFERS the
    /// <see cref="_selectionPaths"/> snapshot (captured while the node was present, so it survives an
    /// in-place mutation where <paramref name="oldItems"/> is the same, already-mutated list); falls
    /// back to walking <paramref name="oldItems"/>; null when neither locates the node.</summary>
    private NodePath? OldPathOf(TreeViewItem<T> sel, List<TreeViewItem<T>>? oldItems)
    {
        if (_selectionPaths.TryGetValue(sel, out var snap)) return snap;
        if (oldItems is null) return null;
        var indices = new List<int>();
        var values = new List<T?>();
        return BuildNodePath(oldItems, sel, indices, values) ? new NodePath(indices, values) : null;
    }

    private void SnapshotSelectionPaths()
    {
        var next = new Dictionary<TreeViewItem<T>, NodePath>(ReferenceEqualityComparer.Instance);
        if (_selectedNodes.Count > 0)
        {
            var tree = Items ?? [];
            foreach (var sel in _selectedNodes)
            {
                var indices = new List<int>();
                var values = new List<T?>();
                if (BuildNodePath(tree, sel, indices, values)) next[sel] = new NodePath(indices, values);
            }
        }
        _selectionPaths = next;
    }

    /// <summary>Drops a single value from BOTH pending buckets AND the seed-origin set (multi-select
    /// supersede) — an explicit interactive selection of a value wins over any deferred seed or
    /// carried identity for it, converting that value from SEEDED to INTERACTIVE.</summary>
    private void RemovePending(T? value)
    {
        if (_pendingSelectValues is not null)
        {
            _pendingSelectValues = _pendingSelectValues
                .Where(v => !EqualityComparer<T>.Default.Equals(v, value))
                .ToList();
            if (_pendingSelectValues.Count == 0) _pendingSelectValues = null;
        }
        if (_pendingCarries is not null)
        {
            _pendingCarries = _pendingCarries
                .Where(c => !EqualityComparer<T>.Default.Equals(c.Value, value))
                .ToList();
            if (_pendingCarries.Count == 0) _pendingCarries = null;
        }
        if (_seededValues is not null)
        {
            _seededValues.Remove(value!);
            if (_seededValues.Count == 0) _seededValues = null;
        }
    }

    /// <summary>Walks a <see cref="NodePath"/> and returns the node at its end ONLY when EVERY segment
    /// resolves unambiguously: at each depth the node at the recorded index must still carry the
    /// recorded value AND that value must be UNIQUE among its immediate siblings. Any shared value at
    /// any segment drops the whole path — the ambiguity-DROP convention.</summary>
    private static TreeViewItem<T>? WalkPath(List<TreeViewItem<T>> roots, NodePath path)
    {
        var indices = path.Indices;
        var values = path.Values;
        if (indices.Count == 0 || indices.Count != values.Count) return null;
        IReadOnlyList<TreeViewItem<T>> level = roots;
        TreeViewItem<T>? node = null;
        for (var d = 0; d < indices.Count; d++)
        {
            var idx = indices[d];
            if (idx < 0 || idx >= level.Count) return null;
            node = level[idx];
            var expected = values[d];
            if (!EqualityComparer<T>.Default.Equals(node.Value, expected)) return null;
            var sameValued = 0;
            foreach (var s in level)
                if (EqualityComparer<T>.Default.Equals(s.Value, expected) && ++sameValued > 1)
                    return null;
            level = node.Children ?? (IReadOnlyList<TreeViewItem<T>>)[];
        }
        return node;
    }

    private static bool BuildNodePath(IReadOnlyList<TreeViewItem<T>> items, TreeViewItem<T> target, List<int> indices, List<T?> values)
    {
        for (int i = 0; i < items.Count; i++)
        {
            var item = items[i];
            indices.Add(i);
            values.Add(item.Value);
            if (ReferenceEquals(item, target)) return true;
            if (item.Children is { Count: > 0 } && BuildNodePath(item.Children, target, indices, values)) return true;
            indices.RemoveAt(indices.Count - 1);
            values.RemoveAt(values.Count - 1);
        }
        return false;
    }

    private static void FlattenAll(List<TreeViewItem<T>> items, List<TreeViewItem<T>> into)
    {
        foreach (var item in items)
        {
            into.Add(item);
            if (item.Children is { Count: > 0 })
                FlattenAll(item.Children, into);
        }
    }

    private static void SetChildrenChecked(List<TreeViewItem<T>>? children, bool value)
    {
        if (children is null) return;
        foreach (var child in children)
        {
            child.IsChecked = value;
            child.IsIndeterminate = false;
            SetChildrenChecked(child.Children, value);
        }
    }

    private static (bool allChecked, bool anyChecked) UpdateAncestorStates(List<TreeViewItem<T>> items)
    {
        bool allChecked = true;
        bool anyChecked = false;

        foreach (var item in items)
        {
            if (item.Children is { Count: > 0 })
            {
                var (childAll, childAny) = UpdateAncestorStates(item.Children);
                if (childAll)
                {
                    item.IsChecked = true;
                    item.IsIndeterminate = false;
                }
                else if (childAny || item.IsChecked)
                {
                    item.IsIndeterminate = true;
                    item.IsChecked = false;
                }
                else
                {
                    item.IsChecked = false;
                    item.IsIndeterminate = false;
                }
            }

            if (item.IsChecked) anyChecked = true;
            else allChecked = false;
            if (item.IsIndeterminate) anyChecked = true;
        }

        return (allChecked, anyChecked);
    }

    private static List<T?> CollectChecked(List<TreeViewItem<T>> items)
    {
        var result = new List<T?>();
        foreach (var item in items)
        {
            if (item.IsChecked) result.Add(item.Value);
            if (item.Children is { Count: > 0 })
                result.AddRange(CollectChecked(item.Children));
        }
        return result;
    }

    /// <summary>Applies an expand/collapse to every node's STATE entry (and mirrors it onto the
    /// record), so a declarative ExpandAll survives a controlled rebuild the same way an interactive
    /// expansion do
… [truncated]

@namespace Lumeo
@typeparam T
@implements IAsyncDisposable
@inject IComponentInteropService Interop

<div class="@RootClass" role="treeitem"
     id="@NodeId"
     aria-expanded="@AriaExpanded"
     aria-selected="@IsSelected.ToString().ToLowerInvariant()"
     aria-disabled="@Item.IsDisabled.ToString().ToLowerInvariant()"
     aria-level="@(Level + 1)"
     aria-posinset="@PosInSet"
     aria-setsize="@SetSize"
     tabindex="@TabIndex"
     @onfocus="HandleFocus"
     @onblur="HandleBlur"
     @onkeydown="HandleKeyDown"
     @onkeydown:stopPropagation="true"
     @attributes="AdditionalAttributes">

    @* Indentation uses the logical inline-start so nesting mirrors correctly under RTL. *@
    <div class="@NodeClass" style="padding-inline-start: @(Level * 16)px" @onclick="HandleClick">

        @* Expand chevron / loading spinner / leaf spacer *@
        @if (Item.IsLoading)
        {
            <span class="shrink-0 p-0.5 w-6 flex items-center justify-center">
                <SvgGlyph Svg="@(LumeoIcons.Loader)" class="h-4 w-4 text-muted-foreground animate-spin" />
            </span>
        }
        else if (ShowExpandChevron && Expandable)
        {
            @* Ghost affordance: NO separate hover background — the whole ROW carries the
               hover highlight (NodeClass' hover:bg-accent/50), so the chevron reads as an
               integrated part of the row (VS Code / shadcn tree style) instead of a detached
               button block. The icon gently brightens on row hover (group-hover/row). A
               focus-visible ring stays for keyboard users; the 24px box keeps a comfortable
               hit/touch target. Still stops propagation, so it toggles without selecting. *@
            <button type="button"
                    class="shrink-0 w-6 h-6 flex items-center justify-center rounded-sm text-muted-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring transition-colors"
                    @onclick="ToggleExpand"
                    @onclick:stopPropagation="true"
                    tabindex="-1"
                    aria-label="@ExpandLabel">
                <SvgGlyph Svg="@(LumeoIcons.ChevronDown)" class="@ChevronClass" />
            </button>
        }
        else
        {
            @* Leaf spacer — matches the 24px chevron/spinner box so labels align across rows. *@
            <span class="w-6"></span>
        }

        @* Checkbox *@
        @if (ShowCheckboxes)
        {
            <span @onclick:stopPropagation="true">
                <Checkbox Checked="@Item.IsChecked"
                          IsIndeterminate="@Item.IsIndeterminate"
                          CheckedChanged="HandleCheck"
                          Disabled="@Item.IsDisabled"
                          Class="me-1" />
            </span>
        }

        @* Label area: custom template OR default icon + text *@
        @if (NodeTemplate is not null)
        {
            @NodeTemplate(Item)
        }
        else
        {
            @if (Item.Icon is { } icon)
            {
                <SvgGlyph Svg="@(icon)" class="@IconClass" />
            }
            <span class="truncate">@Item.Text</span>
        }
    </div>

    @* Children *@
    @if (HasLoadedChildren && EffectiveExpanded)
    {
        var children = VisibleChildren;
        <div role="group">
            @for (var i = 0; i < children.Count; i++)
            {
                var child = children[i];
                <TreeViewNode T="T" @key="child" Item="child" Level="@(Level + 1)"
                              PosInSet="@(i + 1)"
                              SetSize="@children.Count"
                              ShowCheckboxes="ShowCheckboxes"
                              Expandable="Expandable"
                              CascadeCheck="CascadeCheck"
                              MultiSelect="MultiSelect"
                              ExpandOnRowClick="ExpandOnRowClick"
                              SelectedNodes="SelectedNodes"
                              NodeTemplate="NodeTemplate"
                              LoadChildren="LoadChildren"
                              OnItemClick="OnItemClick"
                              OnItemCheck="OnItemCheck"
                              OnSelectionChanged="OnSelectionChanged" />
            }
        </div>
    }
</div>

@code {
    [CascadingParameter] private TreeView<T>.TreeViewContext? Context { get; set; }

    [Parameter] public TreeView<T>.TreeViewItem<T> Item { get; set; } = default!;
    [Parameter] public int Level { get; set; }
    [Parameter] public int PosInSet { get; set; } = 1;
    [Parameter] public int SetSize { get; set; } = 1;
    [Parameter] public bool ShowCheckboxes { get; set; }
    [Parameter] public bool Expandable { get; set; }
    [Parameter] public EventCallback<TreeView<T>.TreeViewItem<T>> OnItemClick { get; set; }
    [Parameter] public EventCallback<TreeView<T>.TreeViewItem<T>> OnItemCheck { get; set; }

    [Parameter] public bool CascadeCheck { get; set; }
    [Parameter] public bool MultiSelect { get; set; }
    // When true (the tree default), clicking anywhere on a PARENT row toggles its
    // expansion in addition to selecting it; false keeps the chevron as the sole
    // expand trigger. Threaded down so every level shares the tree's mode.
    [Parameter] public bool ExpandOnRowClick { get; set; } = true;
    // The set of currently-selected NODE instances (reference-identity comparer, owned by
    // the parent TreeView). Selection is by identity, not Value, so a container node with a
    // null/duplicate Value highlights only itself — see TreeView._selectedNodes (GH #350).
    [Parameter] public HashSet<TreeView<T>.TreeViewItem<T>>? SelectedNodes { get; set; }
    [Parameter] public RenderFragment<TreeView<T>.TreeViewItem<T>>? NodeTemplate { get; set; }
    [Parameter] public Func<TreeView<T>.TreeViewItem<T>, Task<List<TreeView<T>.TreeViewItem<T>>>>? LoadChildren { get; set; }
    [Parameter] public EventCallback<TreeView<T>.TreeViewItem<T>> OnSelectionChanged { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string RootClass => Cx.Merge("group focus-visible:outline-none", Class);

    // Roving tabindex (WAI-ARIA tree pattern): the tree keeps exactly one node —
    // the active one — in the tab sequence; every other node carries -1 and is
    // reached with the arrow keys. Without a cascaded tree context (node rendered
    // standalone) fall back to the legacy root-level behavior.
    private bool _isFocused;
    private string TabIndex => Context is not null
        ? Context.Tree.GetTabIndex(Item).ToString()
        : ((_isFocused || Level == 0) ? "0" : "-1");
    private string ExpandLabel => EffectiveExpanded ? "Collapse" : "Expand";

    // Deterministic id for keyboard-navigation focus targeting; local fallback
    // keeps standalone nodes valid HTML.
    private readonly string _fallbackId = LumeoIds.New("treenode");
    private string NodeId => Context?.Tree.GetNodeId(Item) ?? _fallbackId;

    private bool HasLoadedChildren => Item.Children is { Count: > 0 };

    // Expansion as rendered: the item's own state (mirrored from the tree's state store), plus any
    // search-forced expansion tracked by the parent tree while a filter is active.
    private bool EffectiveExpanded => Context?.Tree.IsEffectivelyExpanded(Item) ?? Item.IsExpanded;

    // Children as rendered: when a search filter is active only the visible
    // subset is rendered; otherwise all loaded children.
    private IReadOnlyList<TreeView<T>.TreeViewItem<T>> VisibleChildren
        => Context is not null
            ? Context.Tree.GetVisibleChildren(Item)
            : (IReadOnlyList<TreeView<T>.TreeViewItem<T>>?)Item.Children ?? [];

    private bool ShowExpandChevron =>
        HasLoadedChildren ||
        (LoadChildren is not null && !Item.IsLeaf && !Item.ChildrenLoaded);

    // Identity match: SelectedNodes uses a reference-equality comparer, so this is true
    // only for the exact clicked node — never for a sibling that shares Item.Value.
    private bool IsSelected => SelectedNodes?.Contains(Item) == true;

    private string? AriaExpanded => ShowExpandChevron
        ? EffectiveExpanded.ToString().ToLowerInvariant()
        : null;

    private string NodeClass
    {
        get
        {
            var parts = new List<string>
            {
                "group/row flex items-center gap-1.5 py-1 px-2 rounded-md transition-colors text-sm group-focus-visible:ring-[1.5px] group-focus-visible:ring-ring group-focus-visible:ring-offset-1",
                Item.IsDisabled ? "opacity-50 cursor-not-allowed text-muted-foreground" : "cursor-pointer hover:bg-accent/50"
            };
            if (IsSelected && !Item.IsDisabled)
                parts.Add("bg-accent text-accent-foreground");
            return string.Join(" ", parts);
        }
    }

    // Single ChevronDown that rotates -90deg when collapsed; smooth like Accordion.
    // Brightens from muted → foreground when the label row is hovered (group-hover/row),
    // an integrated affordance that needs no background block of its own.
    private string ChevronClass => Cx.Join(
        "h-4 w-4 shrink-0 text-muted-foreground group-hover/row:text-foreground transition-transform duration-200",
        Cx.When(!EffectiveExpanded, "-rotate-90"));

    private string IconClass =>
        Item.IsDisabled
            ? "h-4 w-4 text-muted-foreground opacity-50 shrink-0"
            : "h-4 w-4 text-muted-foreground shrink-0";

    private void HandleFocus()
    {
        _isFocused = true;
        // Focus arrived directly (mouse/Tab) — keep the roving tabindex in sync.
        Context?.Tree.SetActive(Item);
    }

    private void HandleBlur()
    {
        _isFocused = false;
    }

    // Expand / collapse is owned by the TREE's state store (TreeView.BeginToggle). The node asks the
    // tree to flip this node's expansion SYNCHRONOUSLY (before any await) and hands back the DEFERRED
    // tail — start the lazy child-load, or notify an already-loaded expand/collapse. The chevron and
    // keyboard run the tail immediately (no selection to order against); the row click runs it only
    // AFTER the selection callbacks. No path snapshots, no post-await re-resolution: the tail mutates
    // a stable state handle that whatever instance now maps to that identity renders (PR #351 rebuild).
    private Task ToggleExpand()
    {
        if (Context is not null)
            return Context.Tree.BeginToggle(Item)();
        // Standalone (no tree context): a plain local flip — no lazy-load / identity survival.
        Item.IsExpanded = !Item.IsExpanded;
        StateHasChanged();
        return Task.CompletedTask;
    }

    // Click semantic (documented): clicking the label ROW always SELECTS the node (and raises
    // OnItemClick). By DEFAULT (ExpandOnRowClick=true) a click on a PARENT row also toggles its
    // expansion (larger hit/touch target; the VS Code file-tree pattern). Leaf rows only select.
    // The chevron button remains an expand/collapse trigger in BOTH modes and stops propagation.
    // A selection-modifier click (Ctrl/Meta/Shift) only mutates selection, never expansion.
    private async Task HandleClick(MouseEventArgs e)
    {
        if (Item.IsDisabled) return;

        // Flip expansion SYNCHRONOUSLY now (in the tree's state store) — before the selection
        // callbacks — so a selection-driven controlled rebuild re-maps the fresh instance to this
        // same state entry and shows it expanded. The lazy child-load is DEFERRED to run isolated
        // AFTER selection, so a slow/throwing loader can neither delay nor kill the selection, and a
        // cached load can't attach ahead of the selection rebuild.
        var deferredExpand = ExpandOnRowClick && Expandable && ShowExpandChevron
            && !IsSelectionModifier(e) && Context is not null
            ? Context.Tree.BeginToggle(Item)
            : null;

        await OnItemClick.InvokeAsync(Item);
        await OnSelectionChanged.InvokeAsync(Item);

        if (deferredExpand is not null)
            await DrainExpansionIsolated(deferredExpand());
    }

    // Drain the lazy-expansion tail AFTER the selection has been applied, absorbing a loader failure
    // so it can neither roll back the (already-committed) selection nor surface as an unhandled
    // circuit exception. The tree's state store has already cleared the spinner and collapsed the
    // branch on failure; the row's contract is to SELECT — surfacing a background branch-load failure
    // is the chevron/keyboard path's job, not the click's.
    private static async Task DrainExpansionIsolated(Task expandTail)
    {
        try { await expandTail; }
        catch (Exception) { /* a lazy-loader failure must not break the completed selection */ }
    }

    // A modifier held during the click is a selection gesture (extend/toggle a multi-selection),
    // not a navigation intent, so row-click expansion is suppressed for it.
    private static bool IsSelectionModifier(MouseEventArgs e)
        => e.CtrlKey || e.MetaKey || e.ShiftKey;

    private async Task HandleCheck(bool value)
    {
        if (Item.IsDisabled) return;
        Item.IsChecked = value;
        if (Item.IsIndeterminate && !value)
            Item.IsIndeterminate = false;
        await OnItemCheck.InvokeAsync(Item);
    }

    // WAI-ARIA tree keyboard pattern. Expand/collapse route through the tree's state store
    // (ToggleExpand); pure focus movement is delegated to the parent tree, which knows the
    // flattened visible order.
    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowDown":
            case "ArrowUp":
            case "Home":
            case "End":
                if (Context is not null)
                    await Context.Tree.HandleNavigationKeyAsync(Item, e.Key);
                break;

            case "ArrowRight":
                if (ShowExpandChevron && Expandable && !EffectiveExpanded)
                    await ToggleExpand();
                else if (Context is not null)
                    await Context.Tree.HandleNavigationKeyAsync(Item, e.Key); // move into first child
                break;

            case "ArrowLeft":
                if (EffectiveExpanded)
                    await ToggleExpand(); // collapse via the state store (honors an in-flight load)
                else if (Context is not null)
                    await Context.Tree.HandleNavigationKeyAsync(Item, e.Key); // move to parent
                break;

            case "Enter":
            case " ":
                if (!Item.IsDisabled)
                {
                    if (ShowCheckboxes)
                    {
                        if (Item.IsIndeterminate)
                        {
                            Item.IsIndeterminate = false;
                            Item.IsChecked = true;
                        }
                        else
                        {
                            Item.IsChecked = !Item.IsChecked;
                        }
                        await OnItemCheck.InvokeAsync(Item);
                    }
                    else
                    {
                        await OnItemClick.InvokeAsync(Item);
                        await OnSelectionChanged.InvokeAsync(Item);
                    }
                }
                break;
        }
    }

    // Suppress page scroll for the focus-moving keys synchronously in JS,
    // against the id the DOM actually carries (a consumer `id` in the splat
    // wins over NodeId). Re-registered when that id changes; prerender-safe.
    private string? _pdRegisteredId;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        var id = LumeoIds.Effective(AdditionalAttributes, NodeId);
        if (_pdRegisteredId == id) return;
        try
        {
            if (_pdRegisteredId is not null)
                await Interop.UnregisterPreventDefaultKeys(_pdRegisteredId);
            await Interop.RegisterPreventDefaultKeys(id, new[]
            {
                new Lumeo.Services.PreventDefaultKeyRule("ArrowDown"),
                new Lumeo.Services.PreventDefaultKeyRule("ArrowUp"),
                new Lumeo.Services.PreventDefaultKeyRule("Home"),
                new Lumeo.Services.PreventDefaultKeyRule("End"),
            });
            _pdRegisteredId = id;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    public async ValueTask DisposeAsync()
    {
        if (_pdRegisteredId is null) return;
        try { await Interop.UnregisterPreventDefaultKeys(_pdRegisteredId); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}
